var sd_sticky_sidebar = function($) {
	return false; // temporarily disable

	var body = $('body');
	var footer = $('.site-footer');
	var main = $('#main');

	var sidebarMain = $('.site-sidebar-main .site-sidebar-slide');
	var sidebarSecondary = $('.site-sidebar-secondary .site-sidebar-slide');

	var contentAreaHeight = $('.post-content').outerHeight(true);
	var postListHeight = $('.post-list').outerHeight(true);

	$(window).on('load', function() {

		if (body.is('.home')) {
			// Homepage sticky sidebar
			var $window = $(window);
			
			var $leftAd = $('.popular-posts-wrapper .widget-widget_ad_widget').first();
			var leftAdTop = $leftAd.offset().top;

			var $rightAd = $('.site-sidebar-main #home-main-sidebar').first();
			var rightAdTop = $rightAd.offset().top;
			
			var endPoint = $('.featured-posts-wrapper article:nth-last-of-type(5)').offset().top;
			
			var scrollPos = 0;
			var timeout;

			var rightAdHasScrolled, leftAdHasScrolled = false;

			$window.on('scroll', function(){
				scrollPos = $window.scrollTop() + 70;

				// right ad
				if ( scrollPos > rightAdTop && scrollPos < endPoint && !rightAdHasScrolled ) {
			        $rightAd.css({ position: 'fixed', top: '70px' });
			        setTimeout(function(){
			        	rightAdHasScrolled = true;
			        	$rightAd.css({ position: 'relative', top: 'auto' });	
			        }, 5000);
				} else if ( !rightAdHasScrolled ) {
					$rightAd.css({ position: 'relative', top: 'auto' });
				} else if ( scrollPos < rightAdTop ) {
					rightAdHasScrolled = false;
				}

				// left ad
				if ( scrollPos > leftAdTop && scrollPos < endPoint && !leftAdHasScrolled ) {
			        $leftAd.css({ position: 'fixed', top: '70px' });
			        setTimeout(function(){
			        	leftAdHasScrolled = true;
			        	$leftAd.css({ position: 'relative', top: 'auto' });	
			        }, 5000);
				} else if ( !leftAdHasScrolled ) {
					$leftAd.css({ position: 'relative', top: 'auto' });
				} else if ( scrollPos < leftAdTop ) {
					leftAdHasScrolled = false;
				}
				
			});

			// var bottomSection = $('.bottom-section');
			// var topSection = $('.top-section');

			// sidebarMain.affix({
			// 	offset: {
			// 		top: main.offset().top - 80,
			// 		bottom: bottomSection.outerHeight(true) + 255
			// 	}
			// });

			// sidebarSecondary.affix({
			// 	offset: {
			// 		top: $('.featured-posts-wrapper').offset().top - 80,
			// 		bottom: bottomSection.outerHeight(true) + 255
			// 	}
			// });
		}

		if (body.is('.archive')) {
			// Archive sticky sidebar
			var sidebar = $('.site-sidebar .site-sidebar-slide');

			if (postListHeight > sidebar.outerHeight(true)) {
				sidebar.affix({
					offset: {
						top: main.offset().top - 80,
						bottom: footer.outerHeight(true) + 50
					}
				});
			}
		}

		if (body.is('.single')) {
			// Article sticky sidebar
			sidebarTotalHeight = sidebarMain.outerHeight(true) + sidebarSecondary.outerHeight(true);

			var tags = $('.tag-list');
			var comments = $('.comments');

			// Give the secondary sidebar room if the comment height is too small
			if (comments.outerHeight(true) < sidebarSecondary.outerHeight(true)) {
				comments.css({
					'height': sidebarSecondary.outerHeight(true)
				});
			}

			// Only stick if content size allows it
			if (contentAreaHeight > sidebarTotalHeight || postListHeight > sidebarTotalHeight) {
				sidebarMain.affix({
					offset: {
						top: main.offset().top - 50,
						bottom: tags.outerHeight(true) + comments.outerHeight(true) + footer.outerHeight(true)
					}
				});

				sidebarSecondary.affix({
					offset: {
						top: comments.offset().top - tags.outerHeight(true),
						bottom: footer.outerHeight(true) + 50
					}
				});

				// Setting the secondary sidebar position so it doesn't overlap the main sidebar
				sidebarSecondary.css({
					'position': 'absolute',
					'top': tags.offset().top
				});

				// Setting the secondary sidebar's position when classes change
				$(window).on('scroll', function() {
					if (sidebarSecondary.is('.affix')) {
						sidebarSecondary.attr('style', '');
					}

					if (sidebarSecondary.is('.affix-top')) {
						sidebarSecondary.css({
							'position': 'absolute',
							'top': tags.offset().top
						});
					}
				});

			}
		}
	});
};
var sd_spot_prices_header = function($) {
	// spot prices in top ticker bar
	var t = document.getElementsByTagName('script')[0];
	var s = document.createElement('script');
	s.async = true;
	s.src = '//integration.nfusionsolutions.biz/client/silverdoctors/widget/module/spotchartheader/nfspotchartheader?platinum=true';
	t.parentNode.insertBefore(s, t);
};

var sd_spot_prices_drawer = function($) {
	// spot prices in top ticker bar
	var t = document.getElementsByTagName('script')[0];
	var s = document.createElement('script');
	s.async = true;
	s.src = '//integration.nfusionsolutions.biz/client/silverdoctors/widget/module/spotchartheader/nfspotchartdrawer';
	t.parentNode.insertBefore(s, t);
};

var sd_site_header = function($) {
	var $body = $('body');
	var $header = $('#site-header');
	var active = 'header-is-active';
	var lastScrollTop;

	function init() {
		newScrollTop = $(this).scrollTop();
		headerHeight = 90;

		$body.addClass(active);

		if (newScrollTop <= headerHeight) {
			$body.removeClass(active);
		}

		lastScrollTop = newScrollTop;
	}

	$(window).on('scroll', function() {
		init();
	});
};
jQuery( window ).ready(function(){
  // For moving down the addvertisment on single post page
  if (jQuery('body').hasClass('single-post')) {
	  var dropPosition = jQuery('.breadcrumb').offset();
	  var elementPosition1 = jQuery('.single-post .popular-posts-wrapper .widget div').offset();
    jQuery(window).scroll(function(){
	    if(jQuery(window).scrollTop() > elementPosition1.top && jQuery(window).scrollTop() < (parseInt(dropPosition.top)+2000) ){
		    jQuery('.single-post .popular-posts-wrapper .widget div > div').css('position','fixed').css('top','70px');
	    }else { 
	      jQuery('.single-post .popular-posts-wrapper .widget div > div').css('position','static');
	    }   
	  });
  }
});

var sd_site_drawer = function($) {

	var slideout = new Slideout({
		panel: document.getElementById('site-wrapper'),
		menu: document.getElementById('site-drawer-wrapper'),
		tolerance: 70,
		side: 'right'
	});

	slideout.disableTouch();

	function close(e) {
		e.preventDefault();
		slideout.close();
	}

	document.querySelector('#drawer-toggle-open').addEventListener('click', function() {
		slideout.open();
	});

	document.querySelector('#drawer-toggle-close').addEventListener('click', function() {
		slideout.close();
	});

	slideout
		.on('beforeopen', function() {
			this.panel.classList.add('panel-open');
		})
		.on('open', function() {
			this.panel.addEventListener('click', close);
		})
		.on('beforeclose', function() {
			this.panel.classList.remove('panel-open');
			this.panel.removeEventListener('click', close);
		});

};

var sd_social_widget = function($) {
	var $form = $('#social-widget-subscribe');
	var $label = $form.find('label');
	var $input = $form.find('input');

	function toggleLabel() {
		if ($input.val() || !$label.hasClass('hidden')) {
			$label.addClass('hidden');
		} else {
			$label.removeClass('hidden');
		}
	}

	$input.on('blur', toggleLabel).on('focus', toggleLabel);
};

var sd_social_sharing = function($) {
	$('.share-on-facebook').on('click', function() {
		elem = $(this);
		postToFeed(elem.data('title'), elem.data('desc'), elem.prop('href'), elem.data('image'));
		return false;
	});

	$('.print-page').on('click', function() {
		window.print();
	});
};

var sd_wpadminbar = function($) {
	var $searchWrapper = $('#wp-admin-bar-search');
	$searchWrapper.append('<button id="adminbarsearch-toggle"><i aria-hidden="true"></i></button>');

	var $searchToggle = $('#adminbarsearch-toggle');

	$searchToggle.on('click', function(e) {
		e.preventDefault();
		if ($searchWrapper.hasClass('is-active')) {
			$searchWrapper.removeClass('is-active');
		} else {
			$searchWrapper.addClass('is-active');
		}
	});
};

jQuery( window ).ready(function( $ ){
	var image = '';
	var url = '';
	var $featuredImage = $( '.featured-image-holder' );
	var $featuredImageurl = $( '.featured-image-link' );
	$('.featured-posts-slider li').on('mouseover', function(){
		
		$('.featured-posts-slider li').removeClass('active');
		$(this).addClass('active');

		image = $(this).data( 'image' );
		$featuredImage.attr( 'src', image );
		
		url = $(this).data( 'url' );
		$featuredImageurl.attr( 'href', url );
	});

	if ( jQuery('.news-ticker').length ) {
	    jQuery('.news-ticker-items').easyTicker({
	        visible: 1,
	        interval: 4000,
	        controls: {
				up: '#new-ticker-next',
				down: '#new-ticker-prev',
				toggle: '#new-ticker-toggle',
			}
	    });
    }

    var isPlaying = true;

    jQuery('#new-ticker-toggle').on('click', function(){
    	if ( isPlaying ) {
    		$(this).removeClass('fa-pause').addClass('fa-play');
    		isPlaying = false;
    	} else {
    		$(this).removeClass('fa-play').addClass('fa-pause');
    		isPlaying = true;
    	}
    });
});
/*
 *@ On Home Page
 *@ For rotating featured articles.
 */
setInterval(function(){ rotate_articles() }, 3000);
function rotate_articles(){
  if(jQuery('.featured_posts_li:hover').length == 0)
  {
    var image = '';
	var url = '';
	var $featuredImage = jQuery( '.featured-image-holder' );
	var $featuredImageurl = jQuery( '.featured-image-link' );
	var next = jQuery('#featured-post-new-slide-silver li.active').removeClass('active').next('li');
	if (next.length ==0)
	{
      jQuery('#featured-post-new-slide-silver li:first').addClass('active');
	}
	else
	{
	  next.addClass('active');
	}
	image = jQuery('#featured-post-new-slide-silver li.active').data( 'image' );
	$featuredImage.attr( 'src', image );
	url = jQuery('#featured-post-new-slide-silver li.active').data( 'url' );
	$featuredImageurl.attr( 'href', url );	
  }
}
//End of rotating featured articles.

